spec.setup_code:
return {
  draw: function(ctx, W, H, t, dt) {
    // Background
    ctx.fillStyle = '#111827';
    ctx.fillRect(0, 0, W, H);

    var duration = 10000;
    var progress = (t % duration) / duration;

    var lineY = H / 2 - 10;
    var lineLen = 180;
    var startX = (W - lineLen) / 2;
    var endX = startX + lineLen;
    var tickInterval = lineLen / 10;

    // Draw number line axis
    ctx.beginPath();
    ctx.moveTo(startX, lineY);
    ctx.lineTo(endX, lineY);
    ctx.strokeStyle = '#4B5563';
    ctx.lineWidth = 3;
    ctx.stroke();

    // Draw ticks & labels
    ctx.font = '10px -apple-system, sans-serif';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'top';

    for (var i = 0; i <= 10; i++) {
      var tx = startX + i * tickInterval;
      ctx.beginPath();
      ctx.moveTo(tx, lineY - 6);
      ctx.lineTo(tx, lineY + 6);
      ctx.strokeStyle = (i === 5) ? '#F59E0B' : '#4B5563'; // Midpoint highlighted
      ctx.lineWidth = (i === 0 || i === 5 || i === 10) ? 2 : 1;
      ctx.stroke();

      if (i === 0) {
        ctx.fillStyle = '#9CA3AF';
        ctx.fillText('4.30', tx, lineY + 10);
      } else if (i === 5) {
        ctx.fillStyle = '#F59E0B';
        ctx.fillText('4.35', tx, lineY + 10);
      } else if (i === 10) {
        ctx.fillStyle = '#9CA3AF';
        ctx.fillText('4.40', tx, lineY + 10);
      }
    }

    // Ball position calculation
    // Start at 4.37 (tick 7)
    var targetTick = 7;
    var ballX = startX + targetTick * tickInterval;

    // Animation stages
    // 0 - 2s: steady at 4.37
    // 2s - 5s: show distance comparison
    // 5s - 8s: roll to 4.40
    // 8s - 10s: hold

    var stage = 1;
    if (progress >= 0.20 && progress < 0.50) stage = 2;
    else if (progress >= 0.50 && progress < 0.80) stage = 3;
    else if (progress >= 0.80) stage = 4;

    var currentBallX = ballX;
    if (stage === 3) {
      var rollProg = (progress - 0.50) / 0.30;
      // Ease in-out roll
      var ease = rollProg * rollProg * (3 - 2 * rollProg);
      currentBallX = ballX + (endX - ballX) * ease;
    } else if (stage === 4) {
      currentBallX = endX;
    }

    // Draw Ball
    ctx.beginPath();
    ctx.arc(currentBallX, lineY, 6, 0, Math.PI * 2);
    ctx.fillStyle = '#EC4899'; // Pink ball
    ctx.fill();
    ctx.strokeStyle = '#FFFFFF';
    ctx.lineWidth = 1.5;
    ctx.stroke();

    // Draw distance markers / guides
    if (stage >= 2 && stage < 4) {
      // Left distance bracket
      ctx.beginPath();
      ctx.moveTo(startX, lineY - 15);
      ctx.quadraticCurveTo(startX + (ballX - startX) / 2, lineY - 30, ballX, lineY - 15);
      ctx.strokeStyle = '#9CA3AF';
      ctx.lineWidth = 1;
      ctx.stroke();
      ctx.fillStyle = '#9CA3AF';
      ctx.font = '10px -apple-system, sans-serif';
      ctx.fillText('7 units', startX + (ballX - startX) / 2, lineY - 38);

      // Right distance bracket
      ctx.beginPath();
      ctx.moveTo(ballX, lineY - 15);
      ctx.quadraticCurveTo(ballX + (endX - ballX) / 2, lineY - 30, endX, lineY - 15);
      ctx.strokeStyle = '#60A5FA';
      ctx.stroke();
      ctx.fillStyle = '#60A5FA';
      ctx.fillText('3 units (closer!)', ballX + (endX - ballX) / 2, lineY - 38);
    }

    // Text annotation
    ctx.textAlign = 'center';
    ctx.textBaseline = 'middle';

    if (stage === 1) {
      ctx.fillStyle = '#F3F4F6';
      ctx.font = 'bold 16px -apple-system, sans-serif';
      ctx.fillText('Plotting 4.37 on Number Line', W / 2, H - 42);
    } else if (stage === 2) {
      ctx.fillStyle = '#F3F4F6';
      ctx.font = 'bold 16px -apple-system, sans-serif';
      ctx.fillText('Checking Distances', W / 2, H - 42);
    } else if (stage === 3) {
      ctx.fillStyle = '#60A5FA';
      ctx.font = 'bold 16px -apple-system, sans-serif';
      ctx.fillText('Rolling to Nearest Tenth...', W / 2, H - 42);
    } else {
      ctx.fillStyle = '#10B981'; // Green for rounded
      ctx.font = 'bold 18px -apple-system, sans-serif';
      ctx.fillText('Rounded UP to 4.4', W / 2, H - 42);
      ctx.fillStyle = '#9CA3AF';
      ctx.font = '12px -apple-system, sans-serif';
      ctx.fillText('Since neighbor 7 is 5 or more', W / 2, H - 22);
    }
  }
};
